function solve(n: number, edges: number[][], k: number): number {
    let max_time = 0;
    for (let edge of edges) {
        if (edge[2] > max_time) {
            max_time = edge[2];
        }
    }

    let low = 0;
    let high = max_time;
    let answer = max_time;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const components = countComponents(n, edges, mid);
        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

function countComponents(n: number, edges: number[][], t: number): number {
    const parent = Array(n).fill(0).map((_, i) => i);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return false;
        }
        parent[rootV] = rootU;
        return true;
    }

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const time = edge[2];
        if (time > t) {
            union(u, v);
        }
    }

    const roots = new Set<number>();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }

    return roots.size;
}
