function solve(n: number, edges: number[][], k: number): number {
    let max_time = 0;
    for (let edge of edges) {
        if (edge[2] > max_time) {
            max_time = edge[2];
        }
    }

    let low = 0;
    let high = max_time;
    let answer = max_time;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const components = countComponents(n, edges, mid);
        if (components >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

